def category_report(records):
    """Return ``(category, count, subtotal)`` rows, highest subtotal first.

    Ties on subtotal break alphabetically by category, matching
    :func:`top_categories`.
    """
    stats = {}
    for r in records:
        count, subtotal = stats.get(r["category"], (0, 0.0))
        stats[r["category"]] = (count + 1, subtotal + r["value"])
    rows = [(category, count, subtotal) for category, (count, subtotal) in stats.items()]
    return sorted(rows, key=lambda row: (-row[2], row[0]))


